t.script:

let isEditMode = false;
let originalFormData = {};
let activeProfileTab = 'basic';

/* ─── Tab switching ─────────────────────────────────────────── */
function switchProfileTab(tabKey) {
    activeProfileTab = tabKey;
    document.querySelectorAll('#personalDetailsForm .profile-tab-section').forEach(card => {
        card.style.display = card.getAttribute('data-tab-group') === tabKey ? '' : 'none';
    });
    document.querySelectorAll('#personalDetailsForm .profile-tab-button').forEach(btn => {
        const active = btn.getAttribute('data-tab-target') === tabKey;
        btn.classList.toggle('active', active);
        btn.setAttribute('aria-selected', active ? 'true' : 'false');
    });
}

/* ─── Sync all toggles and fire enable/disable ──────────────── */
function syncAndToggleEditMode(sourceCheckbox) {
    document.querySelectorAll('.edit-mode-toggle').forEach(t => {
        t.checked = sourceCheckbox.checked;
    });
    sourceCheckbox.checked ? enableEditMode() : disableEditMode();
}

/* ─── Enable edit mode ──────────────────────────────────────── */
function enableEditMode() {
    isEditMode = true;
    document.querySelectorAll('.edit-mode-toggle').forEach(t => t.checked = true);
    storeOriginalFormData();

    document.querySelectorAll('#personalDetailsForm input, #personalDetailsForm select').forEach(input => {
        if (input.type === 'hidden') return;
        if (input.classList.contains('edit-mode-toggle')) return;

        if (input.hasAttribute('data-always-readonly')) {
            input.setAttribute('readonly', 'readonly');
            if (input.tagName === 'SELECT' || input.type === 'checkbox') {
                input.setAttribute('disabled', 'disabled');
            }
            input.style.setProperty('pointer-events', 'none');
            input.style.setProperty('background-color', '#e9ecef');
            return;
        }

        input.removeAttribute('readonly');
        input.removeAttribute('disabled');
        input.style.removeProperty('pointer-events');
        input.style.removeProperty('background-color');
    });

    document.getElementById('formActions').style.display = 'block';
    document.getElementById('viewActions').style.display = 'none';

    document.querySelectorAll('#personalDetailsForm input, #personalDetailsForm select').forEach(input => {
        input.addEventListener('input', validateField);
        input.addEventListener('blur', validateField);
    });
}

/* ─── Disable edit mode ─────────────────────────────────────── */
function disableEditMode() {
    isEditMode = false;
    document.querySelectorAll('.edit-mode-toggle').forEach(t => t.checked = false);

    document.querySelectorAll('#personalDetailsForm input, #personalDetailsForm select').forEach(input => {
        if (input.type === 'hidden') return;
        if (input.classList.contains('edit-mode-toggle')) return;

        if (input.hasAttribute('data-always-readonly')) {
            input.setAttribute('readonly', 'readonly');
            if (input.tagName === 'SELECT' || input.type === 'checkbox') {
                input.setAttribute('disabled', 'disabled');
            }
            input.style.setProperty('pointer-events', 'none');
            input.style.setProperty('background-color', '#e9ecef');
            return;
        }

        input.setAttribute('readonly', 'readonly');
        if (input.tagName === 'SELECT' || input.type === 'checkbox') {
            input.setAttribute('disabled', 'disabled');
        }
        input.style.removeProperty('pointer-events');
        input.style.removeProperty('background-color');
    });

    document.getElementById('formActions').style.display = 'none';
    document.getElementById('viewActions').style.display = 'block';
    clearValidationStates();
}

/* ─── Store original data for cancel ───────────────────────── */
function storeOriginalFormData() {
    const formData = new FormData(document.getElementById('personalDetailsForm'));
    originalFormData = {};
    for (let [key, value] of formData.entries()) {
        originalFormData[key] = value;
    }
}

/* ─── Cancel ────────────────────────────────────────────────── */
function cancelEdit() {
    for (let [key, value] of Object.entries(originalFormData)) {
        const input = document.querySelector(`[name="${key}"]`);
        if (input) input.value = value;
    }
    disableEditMode();
    showMessage('Changes cancelled successfully.', 'info');
}

/* ─── Save as draft ─────────────────────────────────────────── */
function saveAsDraft() {
    const formData = new FormData(document.getElementById('personalDetailsForm'));
    const draftData = {};
    for (let [key, value] of formData.entries()) {
        draftData[key] = value;
    }
    localStorage.setItem('profileDraft', JSON.stringify(draftData));
    showMessage('Profile saved as draft.', 'info');
}

/* ─── Field validation ──────────────────────────────────────── */
function validateField(event) {
    const field = event.target;
    const validationType = field.getAttribute('data-validation');
    let isValid = true;
    let errorMessage = '';
    field.classList.remove('is-valid', 'is-invalid');
    if (validationType) {
        switch (validationType) {
            case 'email':
                if (field.value && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(field.value)) {
                    isValid = false;
                    errorMessage = 'Please enter a valid email address.';
                }
                break;
            case 'phone':
                if (field.value && !/^[+]?[0-9\s\-\(\)]+$/.test(field.value)) {
                    isValid = false;
                    errorMessage = 'Please enter a valid phone number.';
                }
                break;
            case 'required':
                if (!field.value || field.value.trim() === '') {
                    isValid = false;
                    errorMessage = 'This field is required.';
                }
                break;
            case 'date':
                if (field.value && isNaN(new Date(field.value).getTime())) {
                    isValid = false;
                    errorMessage = 'Please enter a valid date.';
                }
                break;
            case 'future-date':
                if (field.value && new Date(field.value) <= new Date()) {
                    isValid = false;
                    errorMessage = 'Date must be in the future.';
                }
                break;
        }
    }
    if (field.value) {
        field.classList.add(isValid ? 'is-valid' : 'is-invalid');
        if (!isValid) {
            const feedback = field.parentNode.querySelector('.invalid-feedback');
            if (feedback) feedback.textContent = errorMessage;
        }
    }
    return isValid;
}

function clearValidationStates() {
    document.querySelectorAll('#personalDetailsForm input, #personalDetailsForm select')
        .forEach(input => input.classList.remove('is-valid', 'is-invalid'));
}

/* ─── Messages ──────────────────────────────────────────────── */
function showMessage(text, type) {
    const container = document.getElementById('messageContainer');
    const successMsg = document.getElementById('successMessage');
    const errorMsg = document.getElementById('errorMessage');
    successMsg.style.display = 'none';
    errorMsg.style.display = 'none';
    successMsg.classList.remove('show');
    errorMsg.classList.remove('show');

    if (type === 'success') {
        document.getElementById('successText').textContent = text;
        successMsg.style.display = 'block';
        successMsg.classList.add('show');
    } else {
        document.getElementById('errorText').textContent = text;
        errorMsg.style.display = 'block';
        errorMsg.classList.add('show');
    }
    container.style.display = 'block';
    container.scrollIntoView({ behavior: 'smooth' });
    setTimeout(() => {
        successMsg.classList.remove('show');
        errorMsg.classList.remove('show');
    }, 5000);
}

/* ─── Form submit ───────────────────────────────────────────── */
document.getElementById('personalDetailsForm').addEventListener('submit', function(e) {
    e.preventDefault();

    let isFormValid = true;
    document.querySelectorAll('#personalDetailsForm input[data-validation], #personalDetailsForm select[data-validation]')
        .forEach(input => { if (!validateField({ target: input })) isFormValid = false; });

    if (!isFormValid) {
        showMessage('Please correct the errors in the form before submitting.', 'error');
        return;
    }

    // Temporarily enable non-always-readonly selects/checkboxes so they are submitted
    const toReenable = [];
    document.querySelectorAll('#personalDetailsForm select[disabled], #personalDetailsForm input[type="checkbox"][disabled]')
        .forEach(el => {
            if (!el.hasAttribute('data-always-readonly')) {
                el.removeAttribute('disabled');
                toReenable.push(el);
            }
        });

    const formData = new FormData(this);
    const csrfToken = document.querySelector('input[name="csrf_token"]').value;

    // Re-disable after capturing formData
    toReenable.forEach(el => el.setAttribute('disabled', 'disabled'));

    fetch('/my/employee/personal', {
        method: 'POST',
        body: formData,
        headers: { 'X-CSRFToken': csrfToken }
    })
    .then(response => response.json())
    .then(data => {
        if (data.success) {
            showMessage('Profile updated successfully!', 'success');
            disableEditMode();
            localStorage.removeItem('profileDraft');
        } else {
            showMessage('Error updating profile: ' + (data.error || 'Unknown error'), 'error');
        }
    })
    .catch(error => {
        console.error('Error:', error);
        showMessage('Network error. Please try again.', 'error');
    });
});

/* ─── DOMContentLoaded ──────────────────────────────────────── */
document.addEventListener('DOMContentLoaded', function() {
    document.querySelectorAll('#personalDetailsForm .profile-tab-button').forEach(button => {
        button.addEventListener('click', function() {
            switchProfileTab(this.getAttribute('data-tab-target'));
        });
    });
    switchProfileTab(activeProfileTab);

    // Restore draft if any
    const draftData = localStorage.getItem('profileDraft');
    if (draftData) {
        try {
            const draft = JSON.parse(draftData);
            Object.entries(draft).forEach(([key, value]) => {
                const input = document.querySelector(`[name="${key}"]`);
                if (input && input.type !== 'hidden') input.value = value;
            });
            showMessage('Draft data loaded. You can continue editing or discard changes.', 'info');
        } catch (e) {
            console.error('Error loading draft:', e);
        }
    }
});
